#include "water_level.h"
#include <Arduino.h>
#define WL_PIN 36
#define WL_THRESHOLD 2000
static int _raw=0;static float _pct=0;static bool _alert=false;
static unsigned long _last=0;
void water_level_setup(){pinMode(WL_PIN,INPUT);Serial.println("[water] OK");}
void water_level_loop(){if(millis()-_last<500)return;_last=millis();_raw=analogRead(WL_PIN);_pct=_raw/4095.0*100.0;_alert=_raw>WL_THRESHOLD;}
int water_level_get_raw(){return _raw;}
float water_level_get_percent(){return _pct;}
bool water_level_alert(){return _alert;}
